// API trả về danh sách câu hỏi, mỗi câu hỏi nên có trường answersCount
// Nếu backend chưa trả về, ta sẽ fetch từng câu hỏi để lấy số lượng answers (không tối ưu)
// Đề xuất: backend trả về answersCount cho mỗi question

import axios from 'axios';

export async function fetchQuestionsWithAnswersCount() {
  const res = await axios.get('http://localhost:8080/api/questions');
  const questions = res.data;
  // Nếu đã có answersCount thì trả về luôn
  if (questions.length && questions[0].answersCount !== undefined) return questions;
  // Nếu chưa có, fetch từng question để lấy answers count
  const withCount = await Promise.all(questions.map(async q => {
    try {
      const ansRes = await axios.get(`http://localhost:8080/api/questions/${q.id || q._id}/answers`);
      return { ...q, answersCount: Array.isArray(ansRes.data) ? ansRes.data.length : 0 };
    } catch {
      return { ...q, answersCount: 0 };
    }
  }));
  return withCount;
}
